  function ciaToggleObsInline(c, anchorBtn){
    try{
      if(!c) return;
      ciaEnsureObsStyle();

      const key = (c && c.key!=null) ? String(c.key) : '';

      // localiza o card alvo (prioridade: botÃ£o clicado -> card mais prÃ³ximo)
      let card = null;
      try{
        if(anchorBtn && anchorBtn.closest) card = anchorBtn.closest('.card[data-key]');
      }catch(_e){}
      if(!card && key){
        try{
          const all = document.querySelectorAll('.card[data-key]');
          for(let i=0;i<all.length;i++){
            const k = all[i].getAttribute('data-key');
            if(String(k) === String(key)){ card = all[i]; break; }
          }
        }catch(_e){}
      }

      // garante card aberto (fluxo esperado: usuÃ¡rio abre card -> clica em Obs)
      try{
        if(card && !card.classList.contains('is-open') && typeof openInline === 'function'){
          openInline(card, c);
        }
      }catch(_e){}

      const slot = card ? card.querySelector('.inline-detail') : null;
      const inner = slot ? (slot.querySelector('.inline-inner') || slot) : null;
      if(!inner){
        // se nÃ£o conseguiu localizar o detalhe inline, nÃ£o abre drawer lateral (UX exigida: dentro do card)
        return;
      }

      // toggle: se jÃ¡ estiver aberto para o mesmo caso, fecha
      if(window.__ciaObsModalKey && window.__ciaObsModalKey === key && window.__ciaObsInlineEl && inner.contains(window.__ciaObsInlineEl)){
        ciaCloseObsModal();
        return;
      }

      ciaCloseObsModal();
      window.__ciaObsModalKey = key || null;

      // cria host dentro do detalhe (antes do histÃ³rico, se existir)
      let host = inner.querySelector('.cia-obs-inline-host');
      if(!host){
        host = document.createElement('div');
        host.className = 'cia-obs-inline-host';
        const hist = inner.querySelector('#histDetails');
        if(hist && hist.parentNode === inner) inner.insertBefore(host, hist);
        else inner.appendChild(host);
      }
      host.innerHTML = '';

      const obs = ciaObsGet(c) || { obs:'', status:'', history:[] };

      const panel = document.createElement('div');
      panel.className = 'cia-obs-inline-panel';
      panel.setAttribute('data-key', key);

      // header
      const h = document.createElement('div'); h.className = 'h';
      const hL = document.createElement('div');
      const ttl = document.createElement('div'); ttl.className = 'ttl'; ttl.textContent = 'ObservaÃ§Ã£o';
      const sub = document.createElement('div'); sub.className = 'sub';
      const cod = (c && c.cod!=null) ? String(c.cod) : '';
      const prod = (c && c.produto!=null) ? String(c.produto) : '';
      const ean = (c && c.ean!=null) ? String(c.ean) : '';
      sub.textContent = [cod, (ean?('EAN '+ean):''), prod].filter(Boolean).join(' â€¢ ');
      hL.appendChild(ttl); hL.appendChild(sub);

      const btnX = document.createElement('button');
      btnX.className = 'btn secondary';
      btnX.type = 'button';
      btnX.textContent = 'Fechar';
      btnX.addEventListener('click', (e)=>{ try{ e.preventDefault(); e.stopPropagation(); try{ e.stopImmediatePropagation && e.stopImmediatePropagation(); }catch(__e){} }catch(_e){}; ciaCloseObsModal(); }, true);

      h.appendChild(hL);
      h.appendChild(btnX);

      // body
      const b = document.createElement('div'); b.className = 'b';
      const row = document.createElement('div'); row.className = 'row';

      const col1 = document.createElement('div');
      const labS = document.createElement('label'); labS.textContent = 'Status';
      const sel = document.createElement('select');
      [
        {v:'', t:'(sem status)'},
        {v:'pendente', t:'Pendente'},
        {v:'acompanhando', t:'Acompanhando'},
        {v:'concluido', t:'ConcluÃ­do'}
      ].forEach(o=>{
        const op = document.createElement('option'); op.value=o.v; op.textContent=o.t; sel.appendChild(op);
      });
      sel.value = ciaObsNormStatus(obs.status||'') || '';
      col1.appendChild(labS); col1.appendChild(sel);

      const col2 = document.createElement('div');
      const labT = document.createElement('label'); labT.textContent = 'ObservaÃ§Ã£o';
      const txt = document.createElement('textarea');
      txt.placeholder = 'Digite a observaÃ§Ã£oâ€¦';
      txt.value = String(obs.obs||'');
      col2.appendChild(labT); col2.appendChild(txt);

      row.appendChild(col1); row.appendChild(col2);
      b.appendChild(row);

      const histBox = document.createElement('div'); histBox.className = 'hist';
      const labH = document.createElement('label'); labH.textContent = 'HistÃ³rico';
      const hist = document.createElement('div');
      hist.className = 'histList';
      ciaRenderObsHistory(hist, obs.history||[]);
      histBox.appendChild(labH); histBox.appendChild(hist);
      b.appendChild(histBox);

      // footer
      const f = document.createElement('div'); f.className = 'f';

      const btnCancel = document.createElement('button');
      btnCancel.className = 'btn secondary';
      btnCancel.type = 'button';
      btnCancel.textContent = 'Cancelar';
      btnCancel.addEventListener('click', (e)=>{ try{ e.preventDefault(); e.stopPropagation(); try{ e.stopImmediatePropagation && e.stopImmediatePropagation(); }catch(__e){} }catch(_e){}; ciaCloseObsModal(); }, true);

      const btnSave = document.createElement('button');
      btnSave.className = 'btn primary';
      btnSave.type = 'button';
      btnSave.textContent = 'Salvar';
      btnSave.addEventListener('click', (e)=>{
        try{ e.preventDefault(); e.stopPropagation(); try{ e.stopImmediatePropagation && e.stopImmediatePropagation(); }catch(__e){} }catch(_e){}
        try{
          const st = ciaObsNormStatus(sel.value||'');
          const ob = String(txt.value||'').trim();

          if(!st && !ob){
            ciaCloseObsModal();
            return;
          }

          const res = ciaObsAppend(c, st, ob, { channel:'inline' });
          const newObs = ciaObsGet(c);

          try{
            if(newObs){
              c.status = ciaObsNormStatus(newObs.status) || c.status;
              c.__ciaObs = newObs;
            }
          }catch(_e){}

          try{ ciaInjectObsButtons(); }catch(_e){}

          try{
            if(anchorBtn && newObs) ciaUpdateObsPill(anchorBtn, newObs);
            const dBtn = document.querySelector('#btnObs');
            if(dBtn && newObs){
              try{ dBtn.classList.add('cia-obs-pill','cia-obs-pill-detail'); }catch(_e){}
              try{ ciaUpdateObsPill(dBtn, newObs); }catch(_e){}
            }
          }catch(_e){}

          try{
            const histArr = (res && res.obj && res.obj.history) ? res.obj.history : (newObs && newObs.history) || [];
            ciaRenderObsHistory(hist, histArr);
          }catch(_e){}

          // CIA_PATCH_FIX28x IMPL1: atualiza histÃ³rico visÃ­vel no detalhe aberto (sem F5)
          try{
            if(typeof ciaInjectVisibleObsHistory === 'function' && inner){
              ciaInjectVisibleObsHistory(inner, c, newObs);
            }
          }catch(_e){}

          // CIA_PATCH_FIX28x IMPL2: atualizaÃ§Ã£o instantÃ¢nea da pÃ­lula no header da lista
          try{
            if(card && typeof ciaFindHeaderMetrics === 'function'){
              var _hdrM = ciaFindHeaderMetrics(card);
              if(_hdrM && typeof ciaUpsertStatusPill === 'function'){
                ciaUpsertStatusPill(_hdrM, ciaObsNormStatus(newObs && newObs.status));
              }
            }
          }catch(_e){}

          try{ if(card) ciaEnsureInlineObsSummary(card); }catch(_e){}

          ciaCloseObsModal();
        }catch(_e){
          ciaCloseObsModal();
        }
      }, true);

      f.appendChild(btnCancel);
      f.appendChild(btnSave);

      panel.appendChild(h);
      panel.appendChild(b);
      panel.appendChild(f);

      host.appendChild(panel);
      window.__ciaObsInlineEl = panel;

      // foco sem rolar a pÃ¡gina
      setTimeout(()=>{ try{ txt.focus({ preventScroll:true }); }catch(_e){ try{ txt.focus(); }catch(__e){} } }, 30);
    }catch(_e){}
  }

