  function ciaInjectObsButtons(){
    try{
      ciaEnsureObsStyle();

      // seletor robusto: o mÃ³dulo usa .card[data-key], mas mantemos fallback por seguranÃ§a
      const cards = Array.from(document.querySelectorAll('.card[data-key], [data-key].card'));
      if(!cards.length) return;

      cards.forEach(card=>{
        const key = card.getAttribute('data-key');
        if(!key) return;

        const c = (state && state.cases) ? state.cases.find(x => String(x.key) === String(key)) : null;
        if(!c) return;

        const obs = ciaObsGet(c);

        // reflete status do Obs no caso e nas pÃ­lulas (topo do card) â€” FIX28x: usa ciaFindHeaderMetrics
        try{
          const st = ciaObsNormStatus(obs && obs.status);
          if(st){ c.status = st; }
          const metrics0 = (typeof ciaFindHeaderMetrics === 'function') ? ciaFindHeaderMetrics(card) : (card.querySelector ? card.querySelector('.metrics') : null);
          if(metrics0) ciaUpsertStatusPill(metrics0, c.status);
        }catch(_e){}

        // FIX28x Watchdog: se card expandido e sem histÃ³rico visÃ­vel, injeta
        try{
          if(card.offsetHeight > 60 && !card.querySelector('[data-cia-obs-hist-visible]')){
            const _det = card.querySelector('.inline-detail');
            if(_det && !_det.hidden){
              const _inr = _det.querySelector('.inline-inner') || _det;
              if(_inr && typeof ciaInjectVisibleObsHistory === 'function'){
                ciaInjectVisibleObsHistory(_inr, c, obs);
              }
            }
          }
        }catch(_e){}

        // atualiza ou cria
        let btn = card.querySelector('.cia-obs-pill[data-in-card="1"]');
        if(btn){
          ciaUpdateObsPill(btn, obs);
          return;
        }

        btn = document.createElement('button');
        btn.type = 'button';
        btn.setAttribute('data-in-card','1');
        btn.setAttribute('data-key', String(key));
        btn.innerHTML = '<span class="mini"></span>Obs';

        // estilo ALWAYS-ON: preferir inserir dentro de .metrics (para nÃ£o sumir por overlap); fallback absoluto no card
        const metrics = card.querySelector ? card.querySelector('.metrics') : null;
        if(metrics){
          // inline pill dentro do fluxo normal
          btn.style.position = 'relative';
          btn.style.top = '';
          btn.style.right = '';
          btn.style.zIndex = '1';
          btn.style.marginRight = '8px';
          btn.style.pointerEvents = 'auto';
          btn.style.display = 'inline-flex';
        }else{
          // fallback: flutua no header do card
          ciaEnsureCardAnchoring(card);
          btn.style.position = 'absolute';
          btn.style.top = '10px';
          btn.style.right = '72px'; // deixa espaÃ§o para badge/Ã­cone de expandir
          btn.style.zIndex = '9999';
          btn.style.pointerEvents = 'auto';
          btn.style.display = 'inline-flex';
        }
        ciaUpdateObsPill(btn, obs);

        // handler local (fallback). O principal Ã© delegaÃ§Ã£o global.
        btn.addEventListener('click', (e)=>{
          e.preventDefault(); e.stopPropagation(); try{ e.stopImmediatePropagation && e.stopImmediatePropagation(); }catch(__e){}
          ciaToggleObsInline(c, btn);
        });

        if(metrics){ metrics.insertBefore(btn, metrics.firstChild); } else { card.appendChild(btn); }
      });
    }catch(_e){}
  }

  function setupObsAlwaysOn(){
    if(window.__ciaObsAlwaysOn) return;
    window.__ciaObsAlwaysOn = true;

    // 1) varredura rÃ¡pida pÃ³s-load (acompanha renderList assÃ­ncrono)
    let tries = 0;
    const id = setInterval(()=>{
      tries++;
      try{ ciaInjectObsButtons(); }catch(_e){}
      if(tries >= 40) clearInterval(id);
    }, 500);

    // 2) observer leve + debounce (re-render / filtros)
    try{
      const root = document.querySelector('#list') || document.querySelector('.list') || document.querySelector('#cards') || document.querySelector('.cards') || document.body;
      let tmo = null;
      const mo = new MutationObserver(()=>{
        if(tmo) clearTimeout(tmo);
        tmo = setTimeout(()=>{ try{ ciaInjectObsButtons(); }catch(_e){} }, 60);
      });
      mo.observe(root, { childList:true, subtree:true });
      window.__ciaObsMO = mo;
    }catch(_e){}
  }


  function setupCardClickFallback(){
    if(window.__ciaCardClickFallback) return;
    window.__ciaCardClickFallback = true;

    document.addEventListener('click', (e)=>{
      try{
        const t = e.target;
        if(!t) return;

        // ignore clicks on injected UI
        if(t.closest && (t.closest('.cia-obs-pill') || t.closest('.cia-obs-btn') || t.closest('.cia-obs-modal') || t.closest('.cia-obs-modal-backdrop'))) return;

        const card = t.closest ? t.closest('.card[data-key]') : null;
        if(!card) return;

        // ignore clicks within expanded detail
        if(t.closest && t.closest('.inline-detail')) return;

        const key = card.getAttribute('data-key');
        if(!key) return;
        openInline(String(key));
      }catch(_e){}
    }, true);
  }

  function setupObservationSystem(){
    if(window.__ciaObsReady) return;
    window.__ciaObsReady = true;

    // patch tagPills to support "pendente"
    try{
      if(typeof tagPills === 'function' && !window.__ciaTagPillsV2){
        window.__ciaTagPillsV2 = true;
        tagPills = function(c){
          const pills = [];
          const mk = function(cls, text){
            return '<span class="pill '+cls+'"><span class="mini"></span>'+escapeHtml(text)+'</span>';
          };
          const st = ciaObsNormStatus(c && c.status);

          if(st === 'concluido') pills.push(mk('ok','ConcluÃ­do'));
          else if(st === 'acompanhando') pills.push(mk('info','Acompanhando'));
          else if(st === 'pendente') pills.push(mk('warn','Pendente'));

          if(c && c.bucket === 'Vencido'){
            const cls = (st === 'concluido') ? 'ok' : (st === 'acompanhando') ? 'info' : 'bad';
            pills.push(mk(cls,'Vencido'));
          }else if(c && c.bucket === '0â€“10 dias') pills.push(mk('bad','0â€“10 dias'));
          else if(c && c.bucket === '11â€“30 dias') pills.push(mk('warn','11â€“30 dias'));
          else if(c && c.bucket === '31â€“60 dias') pills.push(mk('info','31â€“60 dias'));

          if(c && c.qtdeAlta) pills.push(mk('warn','Qtde alta'));
          if(c && c.repetiu) pills.push(mk('info','Repetiu'));

          const f = (c && c.followup) ? c.followup : '';
          if(f==='Sem follow-up') pills.push(mk('bad','Sem follow-up'));
          else if(f==='Follow-up OK') pills.push(mk('ok','Follow-up OK'));

          return pills.join('');
        };
      }
    }catch(_e){}

    setupObsDelegation();
    try{ ciaSetupObsSummaryHook(); }catch(_e){}
    setupCardClickFallback();
    setupObsAlwaysOn();

    // wrap renderList to hydrate status + inject buttons after each render
    if(typeof renderList === 'function' && !window.__ciaRenderListPatched){
      window.__ciaRenderListPatched = true;
      const __renderList = renderList;
      renderList = function(){
        try{
          const cases = (state && state.cases) ? state.cases : [];
          cases.forEach(c=>{
            const obs = ciaObsGet(c);
            if(obs && (obs.status || obs.obs)){
              c.status = ciaObsNormStatus(obs.status) || c.status;
              c.__ciaObs = obs;
            }
          });
        }catch(_e){}
        const out = __renderList.apply(this, arguments);
        try{ ciaInjectObsButtons(); }catch(_e){}
        return out;
      };
    }

    try{ ciaInjectObsButtons(); }catch(_e){}
    try{ ciaEnsureHistDrawerListener(); }catch(_e){}
  }

