  async function dmLoadWeekFromCloud(weekOverride){
    try{
      const week = weekOverride || (dmCloudWeekSelect ? (dmCloudWeekSelect.value || "").trim() : "");
      if(!week){ toast("Selecione uma WEEK para carregar."); return; }

      // Garante que o dropdown tenha essa opÃ§Ã£o e esteja selecionada
      if(dmCloudWeekSelect && week){
        const exists = Array.from(dmCloudWeekSelect.options).some(o => o.value === String(week));
        if(!exists){
          const o = document.createElement("option");
          o.value = String(week);
          o.textContent = "WEEK " + String(week);
          dmCloudWeekSelect.appendChild(o);
        }
        dmCloudWeekSelect.value = String(week);
      }

      // Atualiza contexto
      try{ CIA_CLOUD.setWeek(week); }catch(_e){}
      store.sistWeek = week;
      store.pesqWeekLabel = week;

      const kinds = [
        { db:"mapa", key:"sist", label:"SistemÃ¡tica (Mapa da OperaÃ§Ã£o)" },
        { db:"base_telefones", key:"base", label:"Base de Telefones" },
        { db:"efetividade", key:"efet", label:"Efetividade" },
        { db:"tracking", key:"pesq", label:"Tracking de Pesquisa" },
        { db:"data_critica", key:"datacrit", label:"Data CrÃ­tica" },
        { db:"fotos", key:"fotos", label:"Fotos" }
      ];

      const statusLines = [];
      for(const it of kinds){
        const res = await CIA_CLOUD.downloadLatest(it.db, week);
        if(res && res.file){
          store[it.key] = res.file;
          // Distribui para as telas
          distribute(it.key === "datacrit" ? "datacrit" : it.key);
          statusLines.push({ label: it.label, ok:true, note:"Carregado do cloud e injetado nas telas." });
        }else{
          statusLines.push({ label: it.label, ok:false, note:"NÃ£o encontrei arquivo para essa WEEK." });
        }
      }
      await dmRenderCloudStatus(statusLines);
      toast("Cloud: Week carregada (o que existir) e distribuÃ­da para as telas.");
      try{ if(store.efet) scheduleEfetAuto(); }catch(_e){}
    }catch(e){
      console.warn("[CIA][CLOUD] load week failed", e);
      toast("Cloud: falha ao carregar week. Verifique permissÃµes/RLS e o bucket.");
    }
  }

  // ===== Fotos: Baixar RelatÃ³rio (Host -> frameFotos) =====
  async function downloadPhotosReport(){
    try{ await ensureLoaded('fotos'); }catch(_e){}

    const iframe = document.getElementById('frameFotos');
    if(!iframe || !iframe.contentWindow){
      toast('Tela de Fotos ainda nÃ£o estÃ¡ pronta.', 'warn');
      return;
    }

    const win = iframe.contentWindow;

    // 1) tenta funÃ§Ãµes conhecidas do legado (sequencial, como solicitado)
    for(const fnName of ['exportReport','downloadExcel','generateXLSX']){
      try{
        const fn = win[fnName];
        if(typeof fn === 'function'){
          const r = fn();
          toast('RelatÃ³rio: export solicitado (Fotos).', 'ok');
          return r;
        }
      }catch(_e){}
    }

    // 2) tenta bridge exposta pelo injectOverrides (mais resiliente)
    try{
      if(typeof win.CIA_EXPORT_PHOTOS === 'function'){
        const r = win.CIA_EXPORT_PHOTOS();
        toast('RelatÃ³rio: export solicitado (Fotos).', 'ok');
        return r;
      }
    }catch(_e){}

    // 3) fallback: varre DOM do iframe e tenta clicar no export
    let clicked = false;
    try{
      const doc = iframe.contentDocument;
      if(doc){
        const ids = ['exportReportBtn','btnExportReport','btnExportRelatorio','btnExportRelatÃ³rio','btnRelatorio','btnRelatÃ³rio','exportReport','btnExportXLSX','btnExportXlsx','btnDownloadExcel','downloadExcel','generateXLSX'];
        for(const id of ids){
          const el = doc.getElementById(id);
          if(el && typeof el.click === 'function'){
            el.click();
            clicked = true;
            break;
          }
        }
        if(!clicked){
          const sel = [
            '[data-action="export-report"]',
            '[data-action="exportReport"]',
            '[data-action*="export" i]',
            '[data-action*="excel" i]',
            '[data-action*="xlsx" i]',
            'button[title*="RelatÃ³rio" i]',
            'button[title*="Relatorio" i]',
            'button[aria-label*="RelatÃ³rio" i]',
            'button[aria-label*="Relatorio" i]'
          ].join(',');
          const el2 = doc.querySelector(sel);
          if(el2 && typeof el2.click === 'function'){
            el2.click();
            clicked = true;
          }
        }
      }
    }catch(_e){}

    // 4) Ãºltimo recurso: sinal via postMessage
    if(!clicked){
      try{ win.postMessage({ type:'CIA_EXPORT_PHOTOS' }, '*'); clicked = true; }catch(_e){}
    }

    toast(clicked ? 'RelatÃ³rio: solicitaÃ§Ã£o enviada (Fotos).' : 'NÃ£o encontrei o export de relatÃ³rio dentro da tela de Fotos.', clicked ? 'ok' : 'warn');
  }

