  (function __ciaSafeBootFrames(){
    const keys = Object.keys(frames||{});
    let i = 0;
    const step = ()=>{
      if(i >= keys.length) return;
      const k = keys[i++];
      try{ setFrameDoc(k); }catch(e){ console.error('[CIA] SafeBoot: falha ao carregar mÃ³dulo', k, e); }
      // continua sem bloquear a UI
      if(typeof requestIdleCallback === 'function'){
        requestIdleCallback(step, {timeout:200});
      }else{
        setTimeout(step, 0);
      }
    };
    // inicia apÃ³s garantir que os cliques da sidebar jÃ¡ foram registrados
    setTimeout(step, 0);
  })();

