  function removeLoadedFile(mod){
    // mod: sist | base | fotos | efet | pesq | datacrit
    const cascades = {
      sist:    ['sist','fotos','efet','datacrit'],
      base:    ['fotos','efet','datacrit'],
      fotos:   ['fotos'],
      efet:    ['efet'],
      pesq:    ['pesq'],
      datacrit:['datacrit'],
    };

    const affected = cascades[mod] || [];

    // limpa store
    if(mod==='sist') { store.sist = null; store.sistWeek = 0; }
    if(mod==='base') { store.base = null; }
    if(mod==='fotos') { store.fotos = null; }
    if(mod==='efet') { store.efet = null; store.efetWeekLabel = ''; lastAutoKey = ''; }
    if(mod==='pesq') { store.pesq = null; store.pesqWeekLabel = ''; }
    if(mod==='datacrit') { store.datacrit = null; store.datacritWeekLabel = ''; }

    // limpa input file (para permitir re-upload do mesmo arquivo)
    try {
      if(mod==='sist' && hostInputs.sist) hostInputs.sist.value = '';
      if(mod==='base' && hostInputs.base) hostInputs.base.value = '';
      if(mod==='fotos' && hostInputs.fotos) hostInputs.fotos.value = '';
      if(mod==='efet' && hostInputs.efet) hostInputs.efet.value = '';
      if(mod==='pesq' && hostInputs.pesq) hostInputs.pesq.value = '';
      if(mod==='datacrit' && hostInputs.datacrit) hostInputs.datacrit.value = '';
    } catch (e) {}

    // reseta frames afetados
    affected.forEach(k => _resetFrame(k));

    // status
    try { syncStatusAll(); } catch (e) {}

    // feedback
    try { __ciaToast('Arquivo removido: ' + mod.toUpperCase(), 'info'); } catch (e) {}
  }

