    function genStrongPassword(){
      const alphabet = "ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789!@#$%";
      const buf = new Uint8Array(16);
      crypto.getRandomValues(buf);
      let s = "";
      for(const b of buf) s += alphabet[b % alphabet.length];
      return s;
    }

