  function makeAutoKey(){
    // Efetividade pode processar com apenas o arquivo de Efetividade.
    // SistemÃ¡tica e Base (telefones) sÃ£o opcionais para enriquecimento.
    if(!store.efet) return '';
    const sistPart = store.sist ? [store.sist.name, store.sist.size, store.sist.lastModified] : ['','',''];
    const basePart = store.base ? [store.base.name, store.base.size, store.base.lastModified] : ['','',''];
    return [...sistPart, ...basePart,
            store.efet.name, store.efet.size, store.efet.lastModified].join('|');
  }

  function scheduleEfetAuto(){
    clearTimeout(efetAutoTimer);
    efetAutoTimer = setTimeout(runEfetAuto, 180);
  }

  async function runEfetAuto(){
    const k = makeAutoKey();
    if(!k) return;
    if(k === lastAutoKey) return;

    try{
      await ensureLoaded('efet');
      const doc = safeDoc(frames.efet);
      const win = frames.efet.contentWindow;
      if(!doc) return;

      let did = false;

      // Injeta arquivos disponÃ­veis (Efetividade Ã© obrigatÃ³rio; SistemÃ¡tica/Base sÃ£o opcionais)
      did = setFileOnInput(doc, 'fileEfetividade', store.efet) || did;
      if(store.sist) did = setFileOnInput(doc, 'fileSistematica', store.sist) || did;
      if(store.base) did = setFileOnInput(doc, 'fileBase', store.base) || did;

      // Processa
      if(win && typeof win.processAll === 'function') win.processAll();
      else {
        const btn = doc.getElementById('btnProcessar');
        if(btn) btn.click();
      }

      lastAutoKey = k;
      toast('Efetividade processada automaticamente.');
    }catch(_e){
      // silencia
    }
  }

  // ===== Status sync =====
  function setPillState(el, state, text){
    if(!el) return;
    const dot = el.querySelector('.mini-dot');
    const s = (state||'idle').toLowerCase();
    if(dot){
      dot.classList.remove('ok','bad','warn');
      if(s==='ok') dot.classList.add('ok');
      else if(s==='bad') dot.classList.add('bad');
      else if(s==='warn') dot.classList.add('warn');
      // idle = sem classe extra (fica cinza)
    }
    const label = el.querySelector('.pill-text');
    if(label && typeof text==='string') label.textContent = text;
  }
  function setPill(el, okOrState, text){
    if(okOrState===null || okOrState===undefined) return setPillState(el,'idle',text);
    if(typeof okOrState==='string') return setPillState(el, okOrState, text);
    return setPillState(el, okOrState ? 'ok' : 'bad', text);
  }

